    20→export default function ProfilePage() {
    21→  const { username } = useParams<{ username: string }>();
    22→  const { user, loading: authLoading } = useAuth();
    23→
    24→  const [profile, setProfile] = useState<Profile | null>(null);
    25→  const [loading, setLoading] = useState(true);
    26→  const [notFound, setNotFound] = useState(false);
    27→
    28→  const [activeTab, setActiveTab] = useState<ProfileTab>("guides");
    29→  const [tabData, setTabData] = useState<{ [key in ProfileTab]?: Guide[] | Comment[] }>({});
    30→  const [tabLoading, setTabLoading] = useState(false);
    31→  const [tabVersion, setTabVersion] = useState(0);
    32→
    33→  const isOwner = !!user && !!profile && user.id === profile.id;
    34→
    35→  // Fetch profile
    36→  useEffect(() => {
    37→    if (!username) return;
    38→    setLoading(true);
    39→    fetchProfileByUsername(username)
    40→      .then((p) => {
    41→        if (p) {
    42→          setProfile(p);
    43→          setNotFound(false);
    44→        } else {
    45→          setNotFound(true);
    46→        }
    47→      })
    48→      .finally(() => setLoading(false));
    49→  }, [username]);
    50→
    51→  // Load data when tab, profile, or version changes
    52→  useEffect(() => {
    53→    if (!profile) return;
    54→
    55→    async function load() {
    56→      setTabLoading(true);
    57→      let data: Guide[] | Comment[] = [];
    58→      switch (activeTab) {
    59→        case "guides":
    60→          data = await fetchUserGuides(profile!.id);
    61→          break;
    62→        case "comments":
    63→          data = await fetchUserComments(profile!.id);
    64→          break;
    65→        case "liked":
    66→          data = await fetchUserLikedGuides(profile!.id);
    67→          break;
    68→        case "saved":
    69→          data = await fetchUserSavedGuides(profile!.id);
    70→          break;
    71→      }
    72→      setTabData((prev) => ({ ...prev, [activeTab]: data }));
    73→      setTabLoading(false);
    74→    }
    75→
    76→    if (!tabData[activeTab]) {
    77→      load();
    78→    }
    79→    // eslint-disable-next-line react-hooks/exhaustive-deps
    80→  }, [activeTab, profile?.id, tabVersion]);
    81→
    82→  // Reset tab data when profile updates (e.g. after edit changes privacy)
    83→  function handleProfileUpdate(updated: Profile) {
    84→    setProfile(updated);
    85→    setTabData({});
    86→    setTabVersion((v) => v + 1);
    87→  }
    88→
    89→  // Handle tab change — reset to "guides" if current tab becomes hidden
    90→  function handleTabChange(tab: ProfileTab) {
    91→    setActiveTab(tab);
    92→  }
    93→
    94→  if (loading || authLoading) {
    95→    return (
    96→      <div className="flex items-center justify-center py-20">
    97→        <Loader2 size={24} className="animate-spin text-muted-foreground" />
    98→      </div>
    99→    );
   100→  }
   101→
   102→  if (notFound || !profile) {
   103→    return (
   104→      <div className="flex flex-col items-center justify-center py-20 text-center">
   105→        <div className="mb-4 flex h-20 w-20 items-center justify-center rounded-2xl bg-muted">
   106→          <span className="text-3xl">👤</span>
   107→        </div>
   108→        <h3 className="mb-2 text-lg font-semibold text-foreground">
   109→          User not found
   110→        </h3>
   111→        <p className="max-w-sm text-sm text-muted-foreground">
   112→          The profile you&apos;re looking for doesn&apos;t exist.
   113→        </p>
   114→      </div>
   115→    );
   116→  }
   117→
   118→  const showLiked = profile.show_likes || isOwner;
   119→  const showSaved = profile.show_saves || isOwner;
   120→
   121→  // If active tab is no longer visible, fall back to "guides"
   122→  const effectiveTab =
   123→    (activeTab === "liked" && !showLiked) || (activeTab === "saved" && !showSaved)
   124→      ? "guides"
   125→      : activeTab;
   126→
   127→  const currentData = tabData[effectiveTab];
   128→
   129→  return (
   130→    <div>
   131→      <ProfileHeader
   132→        profile={profile}
   133→        isOwner={isOwner}
   134→        onProfileUpdate={handleProfileUpdate}
   135→      />
   136→
   137→      <div className="mb-6">
   138→        <ProfileTabs
   139→          active={effectiveTab}
   140→          onChange={handleTabChange}
   141→          showLiked={showLiked}
   142→          showSaved={showSaved}
   143→        />
   144→      </div>
   145→
   146→      {tabLoading || !currentData ? (
   147→        <div className="flex items-center justify-center py-20">
   148→          <Loader2 size={24} className="animate-spin text-muted-foreground" />
   149→        </div>
   150→      ) : effectiveTab === "comments" ? (
   151→        <CommentList comments={currentData as Comment[]} />
   152→      ) : (
   153→        <GuideGrid guides={currentData as Guide[]} />
   154→      )}
   155→    </div>
   156→  );
   157→}
