     1→import { createClient } from "@/lib/supabase/client";
     2→import type { Guide } from "@/types";
     3→import type { MediaFile } from "@/components/create/media-upload";
     4→import type { ParsedMessage } from "@/lib/parser/claude-code";
     5→
     6→export async function fetchGuides(sort: string = "trending", search?: string): Promise<Guide[]> {
     7→  const supabase = createClient();
     8→
     9→  let query = supabase
    10→    .from("posts")
    11→    .select(`
    12→      *,
    13→      profile:profiles!posts_user_id_fkey(*),
    14→      media:post_media(*)
    15→    `)
    16→    .eq("is_hidden", false);
    17→
    18→  if (search) {
    19→    query = query.or(`title.ilike.%${search}%,description.ilike.%${search}%`);
    20→  }
    21→
    22→  switch (sort) {
    23→    case "recent":
    24→      query = query.order("created_at", { ascending: false });
    25→      break;
    26→    case "popular":
    27→      query = query.order("likes_count", { ascending: false });
    28→      break;
    29→    case "trending":
    30→    default:
    31→      query = query.order("trending_score", { ascending: false });
    32→      break;
    33→  }
    34→
    35→  const { data, error } = await query.limit(24);
    36→
    37→  if (error) {
    38→    console.error("Failed to fetch guides:", error.message);
    39→    return [];
    40→  }
    41→
    42→  return data as unknown as Guide[];
    43→}
