    75→export function buildCommentTree(flat: Comment[]): Comment[] {
    76→  const map = new Map<string, Comment>();
    77→  const roots: Comment[] = [];
    78→
    79→  for (const c of flat) {
    80→    map.set(c.id, { ...c, replies: [] });
    81→  }
    82→
    83→  for (const c of flat) {
    84→    const node = map.get(c.id)!;
    85→    if (c.parent_id && map.has(c.parent_id)) {
    86→      map.get(c.parent_id)!.replies!.push(node);
    87→    } else {
    88→      roots.push(node);
    89→    }
    90→  }
    91→
    92→  return roots;
    93→}
